using System.ComponentModel.DataAnnotations;

namespace DocSummary.Models;

public class SummarizeRequest
{
    [Required]
    [MinLength(1)]
    public required string Text { get; set; }

    /// <summary>
    /// Maximum number of sentences to include in the summary.
    /// Defaults to 3.
    /// </summary>
    [Range(1, 100)]
    public int MaxSentences { get; set; } = 3;
}

namespace DocSummary.Models;

public class SummarizeResponse
{
    public required string Summary { get; set; }
    public int OriginalLength { get; set; }
    public int SummaryLength { get; set; }
}

namespace DocSummary.Services;

public interface IDocumentSummaryService
{
    string Summarize(string text, int maxSentences);
}

using System.Text.RegularExpressions;

namespace DocSummary.Services;

/// <summary>
/// Extractive summarizer that ranks sentences by word-frequency
/// scoring and returns the top-ranked ones in their original order.
/// </summary>
public partial class DocumentSummaryService : IDocumentSummaryService
{
    private static readonly HashSet<string> StopWords = new(StringComparer.OrdinalIgnoreCase)
    {
        "a","an","the","and","or","but","is","are","was","were","be","been",
        "being","have","has","had","do","does","did","will","would","shall",
        "should","may","might","must","can","could","i","you","he","she","it",
        "we","they","me","him","her","us","them","my","your","his","its","our",
        "their","this","that","these","those","in","on","at","to","for","of",
        "with","by","from","as","into","about","between","through","during",
        "before","after","above","below","not","no","nor","so","if","then",
        "than","too","very","just","also","more","most","such","each","every",
        "all","any","few","some","many","much","own","other","another","only"
    };

    public string Summarize(string text, int maxSentences)
    {
        var sentences = SplitIntoSentences(text);

        if (sentences.Count <= maxSentences)
            return string.Join(" ", sentences);

        var wordFrequencies = BuildWordFrequencies(sentences);
        var scores = ScoreSentences(sentences, wordFrequencies);

        // Pick the top-scoring sentences, then reorder by original position.
        var topIndices = scores
            .Select((score, index) => (score, index))
            .OrderByDescending(x => x.score)
            .Take(maxSentences)
            .Select(x => x.index)
            .Order()
            .ToList();

        return string.Join(" ", topIndices.Select(i => sentences[i]));
    }

    private static List<string> SplitIntoSentences(string text)
    {
        return SentenceBoundary()
            .Split(text)
            .Select(s => s.Trim())
            .Where(s => s.Length > 0)
            .ToList();
    }

    private static Dictionary<string, int> BuildWordFrequencies(List<string> sentences)
    {
        var freq = new Dictionary<string, int>(StringComparer.OrdinalIgnoreCase);
        foreach (var sentence in sentences)
        {
            foreach (var word in Tokenize(sentence))
            {
                if (!StopWords.Contains(word))
                    freq[word] = freq.GetValueOrDefault(word) + 1;
            }
        }
        return freq;
    }

    private static List<double> ScoreSentences(
        List<string> sentences,
        Dictionary<string, int> wordFrequencies)
    {
        var scores = new List<double>(sentences.Count);
        foreach (var sentence in sentences)
        {
            var words = Tokenize(sentence);
            if (words.Count == 0)
            {
                scores.Add(0);
                continue;
            }

            double score = words
                .Where(w => !StopWords.Contains(w))
                .Sum(w => wordFrequencies.GetValueOrDefault(w));

            // Normalize by word count to avoid bias toward long sentences.
            scores.Add(score / words.Count);
        }
        return scores;
    }

    private static List<string> Tokenize(string text)
    {
        return WordPattern()
            .Matches(text)
            .Select(m => m.Value)
            .ToList();
    }

    [GeneratedRegex(@"(?<=[.!?])\s+", RegexOptions.Compiled)]
    private static partial Regex SentenceBoundary();

    [GeneratedRegex(@"\b[a-zA-Z']+\b", RegexOptions.Compiled)]
    private static partial Regex WordPattern();
}

using DocSummary.Models;
using DocSummary.Services;
using Microsoft.AspNetCore.Mvc;

namespace DocSummary.Controllers;

[ApiController]
[Route("api/[controller]")]
public class SummaryController(IDocumentSummaryService summaryService) : ControllerBase
{
    /// <summary>
    /// Accepts document text and returns a concise extractive summary.
    /// </summary>
    [HttpPost]
    public ActionResult<SummarizeResponse> Summarize([FromBody] SummarizeRequest request)
    {
        var summary = summaryService.Summarize(request.Text, request.MaxSentences);

        return Ok(new SummarizeResponse
        {
            Summary = summary,
            OriginalLength = request.Text.Length,
            SummaryLength = summary.Length
        });
    }
}

